async function generateIconTypeDefinitions(
  collections: IconCollection[],
  rootDir: URL,
  defaultPack = "local",
): Promise<void> {
  const typeFile = new URL("./.astro/icon.d.ts", rootDir);
  await ensureDir(new URL("./", typeFile));
  const oldHash = await tryGetHash(typeFile);
  const currentHash = collectionsHash(collections);
  if (currentHash === oldHash) {
    return;
  }
  await writeFile(
    typeFile,
    `// Automatically generated by astro-icon
// ${currentHash}

declare module 'virtual:astro-icon' {
\texport type Icon = ${
      collections.length > 0
        ? collections
            .map((collection) =>
              Object.keys(collection.icons)
                .concat(Object.keys(collection.aliases ?? {}))
                .map(
                  (icon) =>
                    `\n\t\t| "${
                      collection.prefix === defaultPack
                        ? ""
                        : `${collection.prefix}:`
                    }${icon}"`,
                ),
            )
            .flat(1)
            .join("")
        : "never"
    };
}`,
  );
}

export function getNetworkAddress(
	// biome-ignore lint/style/useDefaultParameterLast: <explanation>
	protocol: 'http' | 'https' = 'http',
	hostname: string | undefined,
	port: number,
	base?: string
) {
	const NetworkAddress: NetworkAddressOpt = {
		local: [],
		network: [],
	};
	// biome-ignore lint/complexity/noForEach: <explanation>
	Object.values(os.networkInterfaces())
		.flatMap((nInterface) => nInterface ?? [])
		.filter(
			(detail) =>
				// biome-ignore lint/complexity/useOptionalChain: <explanation>
				detail &&
				detail.address &&
				(detail.family === 'IPv4' ||
					// @ts-expect-error Node 18.0 - 18.3 returns number
					detail.family === 4)
		)
		.forEach((detail) => {
			let host = detail.address.replace(
				'127.0.0.1',
				hostname === undefined || wildcardHosts.has(hostname) ? 'localhost' : hostname
			);
			// ipv6 host
			if (host.includes(':')) {
				host = `[${host}]`;
			}
			const url = `${protocol}://${host}:${port}${base ? base : ''}`;
			if (detail.address.includes('127.0.0.1')) {
				NetworkAddress.local.push(url);
			} else {
				NetworkAddress.network.push(url);
			}
		});
	return NetworkAddress;
}

export function createServer(listener: http.RequestListener, host: string, port: number) {
	let httpServer: http.Server | https.Server;

	if (process.env.SERVER_CERT_PATH && process.env.SERVER_KEY_PATH) {
		httpServer = https.createServer(
			{
				key: fs.readFileSync(process.env.SERVER_KEY_PATH),
				cert: fs.readFileSync(process.env.SERVER_CERT_PATH),
			},
			listener
		);
	} else {
		httpServer = http.createServer(listener);
	}
	enableDestroy(httpServer);

	// Resolves once the server is closed
	const closed = new Promise<void>((resolve, reject) => {
		httpServer.addListener('close', resolve);
		httpServer.addListener('error', reject);
	});

	const previewable = {
		host,
		port,
		closed() {
			return closed;
		},
		async stop() {
			await new Promise((resolve, reject) => {
				httpServer.destroy((err) => (err ? reject(err) : resolve(undefined)));
			});
		},
	} satisfies PreviewServer;

	return {
		server: httpServer,
		...previewable,
	};
}

export function validateI18nFallback(
	i18n: Pick<I18nConfig, 'defaultLocale' | 'locales' | 'fallback'>,
): ConfigValidationIssue[] {
	const issues: ConfigValidationIssue[] = [];
	const { defaultLocale, fallback } = i18n;
	if (!fallback) return [];

	const locales = i18n.locales.map((locale) => (typeof locale === 'string' ? locale : locale.path));

	for (const [fallbackFrom, fallbackTo] of Object.entries(fallback)) {
		if (!locales.includes(fallbackFrom)) {
			issues.push({
				message: `The locale \`${fallbackFrom}\` key in the \`i18n.fallback\` record doesn't exist in the \`i18n.locales\` array.`,
				path: ['i18n', 'fallbacks'],
			});
		}

		if (fallbackFrom === defaultLocale) {
			issues.push({
				message: `You can't use the default locale as a key. The default locale can only be used as value.`,
				path: ['i18n', 'fallbacks'],
			});
		}

		if (!locales.includes(fallbackTo)) {
			issues.push({
				message: `The locale \`${fallbackTo}\` value in the \`i18n.fallback\` record doesn't exist in the \`i18n.locales\` array.`,
				path: ['i18n', 'fallbacks'],
			});
		}
	}
	return issues;
}

export function validateGetStaticPathsResult(result: GetStaticPathsResult, route: RouteData) {
	if (!Array.isArray(result)) {
		throw new AstroError({
			...AstroErrorData.InvalidGetStaticPathsReturn,
			message: AstroErrorData.InvalidGetStaticPathsReturn.message(typeof result),
			location: {
				file: route.component,
			},
		});
	}

	result.forEach((pathObject) => {
		if ((typeof pathObject === 'object' && Array.isArray(pathObject)) || pathObject === null) {
			throw new AstroError({
				...AstroErrorData.InvalidGetStaticPathsEntry,
				message: AstroErrorData.InvalidGetStaticPathsEntry.message(
					Array.isArray(pathObject) ? 'array' : typeof pathObject,
				),
			});
		}

		if (
			pathObject.params === undefined ||
			pathObject.params === null ||
			(pathObject.params && Object.keys(pathObject.params).length === 0)
		) {
			throw new AstroError({
				...AstroErrorData.GetStaticPathsExpectedParams,
				location: {
					file: route.component,
				},
			});
		}
	});
}

function getTemplates({
	schema,
	validatedVariables,
	loadedEnv,
}: {
	schema: EnvSchema;
	validatedVariables: Array<ValidVariable>;
	loadedEnv: Record<string, string> | null;
}) {
	let client = '';
	let server = (cachedServerTemplate ??= readFileSync(MODULE_TEMPLATE_URL, 'utf-8'));
	let onSetGetEnv = '';

	for (const { key, value, context } of validatedVariables) {
		const str = `export const ${key} = ${JSON.stringify(value)};`;
		if (context === 'client') {
			client += str;
		} else {
			server += str;
		}
	}

	for (const [key, options] of Object.entries(schema)) {
		if (!(options.context === 'server' && options.access === 'secret')) {
			continue;
		}

		server += `export let ${key} = _internalGetSecret(${JSON.stringify(key)});\n`;
		onSetGetEnv += `${key} = _internalGetSecret(${JSON.stringify(key)});\n`;
	}

	server = server.replace('// @@ON_SET_GET_ENV@@', onSetGetEnv);
	if (loadedEnv) {
		server = server.replace('// @@GET_ENV@@', `return (${JSON.stringify(loadedEnv)})[key];`);
	} else {
		server = server.replace('// @@GET_ENV@@', 'return _getEnv(key);');
	}

	return {
		client,
		server,
	};
}

attachEvents() {
	const items = this.shadowRoot.querySelectorAll<HTMLDivElement>('.item');
	items.forEach((item) => {
		item.addEventListener('click', async (event) => {
			const target = event.currentTarget;
			if (!target || !(target instanceof HTMLElement)) return;
			const id = target.dataset.appId;
			if (!id) return;
			const app = this.getAppById(id);
			if (!app) return;
			event.stopPropagation();
			await this.toggleAppStatus(app);
		});
	});

	(['mouseenter', 'focusin'] as const).forEach((event) => {
		this.devToolbarContainer!.addEventListener(event, () => {
			this.clearDelayedHide();
			if (this.isHidden()) {
				this.setToolbarVisible(true);
			}
		});
	});

	(['mouseleave', 'focusout'] as const).forEach((event) => {
		this.devToolbarContainer!.addEventListener(event, () => {
			this.clearDelayedHide();
			if (this.getActiveApp() || this.isHidden()) {
				return;
			}
			this.triggerDelayedHide();
		});
	});

	document.addEventListener('keyup', (event) => {
		if (event.key !== 'Escape') return;
		if (this.isHidden()) return;
		const activeApp = this.getActiveApp();
		if (activeApp) {
			this.toggleAppStatus(activeApp);
		} else {
			this.setToolbarVisible(false);
		}
	});
}

async initApp(app: DevToolbarApp) {
	const shadowRoot = this.getAppCanvasById(app.id)!.shadowRoot!;
	app.status = 'loading';
	try {
		settings.logger.verboseLog(`Initializing app ${app.id}`);

		await app.init?.(shadowRoot, app.eventTarget, serverHelpers);
		app.status = 'ready';

		if (import.meta.hot) {
			import.meta.hot.send(`${WS_EVENT_NAME}:${app.id}:initialized`);
		}
	} catch (e) {
		console.error(`Failed to init app ${app.id}, error: ${e}`);
		app.status = 'error';

		if (import.meta.hot) {
			import.meta.hot.send('astro:devtoolbar:error:init', {
				app: app,
				error: e instanceof Error ? e.stack : e,
			});
		}

		const appButton = this.getAppButtonById(app.id);
		const appTooltip = appButton?.querySelector<HTMLElement>('.item-tooltip');

		if (appButton && appTooltip) {
			appButton.toggleAttribute('data-app-error', true);
			appTooltip.innerText = `Error initializing ${app.name}`;
		}
	}
}

export function slide({
	duration,
}: {
	duration?: string | number;
} = {}): TransitionDirectionalAnimations {
	return {
		forwards: {
			old: [
				{
					name: 'astroFadeOut',
					duration: duration ?? '90ms',
					easing: EASE_IN_OUT_QUART,
					fillMode: 'both',
				},
				{
					name: 'astroSlideToLeft',
					duration: duration ?? '220ms',
					easing: EASE_IN_OUT_QUART,
					fillMode: 'both',
				},
			],
			new: [
				{
					name: 'astroFadeIn',
					duration: duration ?? '210ms',
					easing: EASE_IN_OUT_QUART,
					delay: duration ? undefined : '30ms',
					fillMode: 'both',
				},
				{
					name: 'astroSlideFromRight',
					duration: duration ?? '220ms',
					easing: EASE_IN_OUT_QUART,
					fillMode: 'both',
				},
			],
		},
		backwards: {
			old: [{ name: 'astroFadeOut' }, { name: 'astroSlideToRight' }],
			new: [{ name: 'astroFadeIn' }, { name: 'astroSlideFromLeft' }],
		},
	};
}

export function vitePluginApp(): vite.Plugin[] {
	let command: vite.ResolvedConfig['command'];
	return [
		{
			name: 'astro:app',
			configResolved(config) {
				command = config.command;
			},
			resolveId: {
				filter: {
					id: new RegExp(`^${ASTRO_APP_ID}$`),
				},
				handler() {
					return RESOLVED_ASTRO_APP_ID;
				},
			},
			load: {
				filter: {
					id: new RegExp(`^${RESOLVED_ASTRO_APP_ID}$`),
				},
				handler() {
					const entrypoint =
						command === 'serve' ? 'astro/app/entrypoint/dev' : 'astro/app/entrypoint/prod';

					const code = `export { createApp } from '${entrypoint}';`;

					return {
						code,
					};
				},
			},
		},
		{
			name: 'astro:server-app',
			resolveId: {
				filter: {
					id: new RegExp(`^${ASTRO_DEV_SERVER_APP_ID}$`),
				},
				handler() {
					const url = new URL('./createAstroServerApp.js', import.meta.url);
					return this.resolve(url.toString());
				},
			},
		},
	];
}

function send(req, res, file, stats, headers) {
	let code = 200,
		tmp,
		opts = {};
	headers = { ...headers };

	for (let key in headers) {
		tmp = res.getHeader(key);
		if (tmp) headers[key] = tmp;
	}

	if ((tmp = res.getHeader('content-type'))) {
		headers['Content-Type'] = tmp;
	}

	if (req.headers.range) {
		code = 206;
		let [x, y] = req.headers.range.replace('bytes=', '').split('-');
		let end = (opts.end = Number.parseInt(y, 10) || stats.size - 1);
		let start = (opts.start = Number.parseInt(x, 10) || 0);

		if (start >= stats.size || end >= stats.size) {
			res.setHeader('Content-Range', `bytes */${stats.size}`);
			res.statusCode = 416;
			return res.end();
		}

		headers['Content-Range'] = `bytes ${start}-${end}/${stats.size}`;
		headers['Content-Length'] = end - start + 1;
		headers['Accept-Ranges'] = 'bytes';
	}

	res.writeHead(code, headers);
	const stream = fs.createReadStream(file, opts);
	stream.pipe(res);
	res.on('close', () => stream.destroy());
}

function getAdapter({
	middlewareMode,
	skewProtection,
	buildOutput,
	staticHeaders,
}: {
	buildOutput: 'server' | 'static';
	middlewareMode: NonNullable<VercelServerlessConfig['middlewareMode']>;
	skewProtection: boolean;
	staticHeaders: NonNullable<VercelServerlessConfig['staticHeaders']>;
}): AstroAdapter {
	return {
		name: PACKAGE_NAME,
		entrypointResolution: 'auto',
		serverEntrypoint: `${PACKAGE_NAME}/entrypoint`,
		adapterFeatures: {
			buildOutput,
			middlewareMode,
			staticHeaders,
		},
		supportedAstroFeatures: {
			hybridOutput: 'stable',
			staticOutput: 'stable',
			serverOutput: 'stable',
			sharpImageService: 'stable',
			i18nDomains: 'experimental',
			envGetSecret: 'stable',
		},
		client: {
			internalFetchHeaders: skewProtection
				? (): Record<string, string> => {
						const deploymentId = process.env.VERCEL_DEPLOYMENT_ID;
						if (deploymentId) {
							return { 'x-deployment-id': deploymentId };
						}
						return {};
					}
				: undefined,
			assetQueryParams:
				skewProtection && process.env.VERCEL_DEPLOYMENT_ID
					? new URLSearchParams({ dpl: process.env.VERCEL_DEPLOYMENT_ID })
					: undefined,
		},
	};
}

export function createImageMarkerPlugin(
	localImagePaths: Set<string>,
	remoteImagePaths: Set<string>,
): HastPluginDefinition {
	const indexBySrc = new Map<string, number>();
	return {
		name: 'image-marker',
		element: {
			filter: ['img'],
			visit(node, ctx) {
				const props = (node.properties ?? {}) as Record<string, unknown>;
				const rawSrc = typeof props.src === 'string' ? props.src : undefined;
				if (!rawSrc) return;
				const src = decodeURI(rawSrc);

				const isLocal = localImagePaths.has(src);
				const isRemote = !isLocal && remoteImagePaths.has(src);
				if (!isLocal && !isRemote) return;

				const { src: _src, ...rest } = props;
				const index = indexBySrc.get(rawSrc) ?? 0;
				indexBySrc.set(rawSrc, index + 1);

				const imageProperties: Record<string, unknown> = { ...rest, src, index };
				if (isRemote && !('width' in props) && !('height' in props)) {
					imageProperties.inferSize = true;
				}

				ctx.setProperty(node, '__ASTRO_IMAGE_', JSON.stringify(imageProperties));
				for (const key of Object.keys(rest)) {
					if (!HAST_PRESERVED_PROPERTIES.has(key)) {
						ctx.setProperty(node, key, null);
					}
				}
				ctx.setProperty(node, 'src', null);
			},
		},
	};
}

async function bundle(files) {
	const { metafile } = await build({
		entryPoints: [
			...files.map(({ filename }) => filename),
			...files.map(({ filename }) => `main/${filename}`).filter((f) => existsSync(f)),
		],
		bundle: true,
		minify: true,
		sourcemap: false,
		target: ['esnext'],
		outdir: 'out',
		external: ['astro:*', 'aria-query', 'axobject-query'],
		metafile: true,
	});

	return Object.entries(metafile.outputs).reduce((acc, [filename, info]) => {
		filename = filename.slice('out/'.length);
		if (filename.startsWith('main/')) {
			filename = filename.slice('main/'.length).replace(CLIENT_RUNTIME_PATH, '').replace('.js', '');
			const oldSize = info.bytes;
			return Object.assign(acc, {
				[filename]: Object.assign(acc[filename] ?? { oldSize: 0, newSize: 0 }, { oldSize }),
			});
		}
		filename = filename.replace(CLIENT_RUNTIME_PATH, '').replace('.js', '');
		const newSize = info.bytes;
		return Object.assign(acc, {
			[filename]: Object.assign(acc[filename] ?? { oldSize: 0, newSize: 0 }, {
				newSize,
				sourceFile: Object.keys(info.inputs).find((src) => src.endsWith('.ts')),
			}),
		});
	}, {});
}

export default function astroIntegrationActionsRouteHandler({
	settings,
	filename,
}: {
	settings: AstroSettings;
	filename: string;
}): AstroIntegration {
	return {
		name: VIRTUAL_MODULE_ID,
		hooks: {
			async 'astro:config:setup'() {
				settings.injectedRoutes.push({
					pattern: ACTION_RPC_ROUTE_PATTERN,
					entrypoint: 'astro/actions/runtime/entrypoints/route.js',
					prerender: false,
					origin: 'internal',
				});
			},
			'astro:config:done': async (params) => {
				const stringifiedActionsImport = JSON.stringify(
					viteID(new URL(`./${filename}`, params.config.srcDir)),
				);
				settings.injectedTypes.push({
					filename: ACTIONS_TYPES_FILE,
					content: `declare module "astro:actions" {
		export const actions: typeof import(${stringifiedActionsImport})["server"];
}`,
				});
			},
			'astro:routes:resolved': ({ routes }) => {
				if (!settings.config.adapter && !hasNonPrerenderedRoute(routes)) {
					const error = new AstroError(ActionsWithoutServerOutputError);
					error.stack = undefined;
					throw error;
				}
			},
		},
	};
}

export function resolveSharpEncoderOptions(
	transform: Pick<BaseServiceTransform, 'format' | 'quality'>,
	inputFormat: string | undefined,
	serviceConfig: SharpImageServiceConfig = {},
): JpegOptions | PngOptions | WebpOptions | AvifOptions | { quality?: number } | undefined {
	const quality = resolveSharpQuality(transform.quality);

	if (transform.format === undefined) {
		return quality === undefined ? undefined : { quality };
	}

	switch (transform.format) {
		case 'jpg':
		case 'jpeg':
			return {
				...serviceConfig.jpeg,
				...(quality === undefined ? {} : { quality }),
			};
		case 'png':
			return {
				...serviceConfig.png,
				...(quality === undefined ? {} : { quality }),
			};
		case 'webp': {
			const webpOptions: WebpOptions = {
				...serviceConfig.webp,
				...(quality === undefined ? {} : { quality }),
			};
			if (inputFormat === 'gif') {
				webpOptions.loop ??= 0;
			}
			return webpOptions;
		}
		case 'avif':
			return {
				...serviceConfig.avif,
				...(quality === undefined ? {} : { quality }),
			};
		default:
			return quality === undefined ? undefined : { quality };
	}
}

async execute(
	command: string,
	args?: Array<string>,
	options?: CommandExecutorOptions,
): Promise<{ stdout: string }> {
	const proc = x(command, args, {
		throwOnError: true,
		nodeOptions: {
			cwd: options?.cwd,
			env: options?.env,
			shell: options?.shell,
			stdio: options?.stdio,
		},
	});
	if (options?.input) {
		proc.process?.stdin?.end(options.input);
	}
	return await proc.then(
		(o) => o,
		(e) => {
			if (e instanceof NonZeroExitError) {
				const fullCommand = args?.length
					? `${command} ${args.map((a) => (a.includes(' ') ? `"${a}"` : a)).join(' ')}`
					: command;
				const message = `The command \`${fullCommand}\` exited with code ${e.exitCode}`;
				const newError = new Error(message, e.cause ? { cause: e.cause } : undefined);
				(newError as any).stderr = e.output?.stderr;
				(newError as any).stdout = e.output?.stdout;
				throw newError;
			}
			throw e;
		},
	);
}

#warnMissingFeatures(): void {
	if (this.#featureCheckDone || !this.#hasCustomFetchHandler) return;
	this.#featureCheckDone = true;

	const manifest = this.manifest;
	const missing: string[] = [];

	const used = this.pipeline.usedFeatures;

	if (
		manifest.routes.some((r) => r.routeData.type === 'redirect') &&
		!(used & PipelineFeatures.redirects)
	) {
		missing.push('redirects');
	}
	if (manifest.sessionConfig && !(used & PipelineFeatures.sessions)) {
		missing.push('sessions');
	}
	if (manifest.actions && !(used & PipelineFeatures.actions)) {
		missing.push('actions');
	}
	if (manifest.middleware && !(used & PipelineFeatures.middleware)) {
		missing.push('middleware');
	}
	if (manifest.i18n && manifest.i18n.strategy !== 'manual' && !(used & PipelineFeatures.i18n)) {
		missing.push('i18n');
	}
	if (manifest.cacheConfig && !(used & PipelineFeatures.cache)) {
		missing.push('cache');
	}

	for (const feature of missing) {
		this.logger.warn(
			'router',
			`Your project uses ${feature}, but your custom src/app.ts does not call the ${feature}() handler. ` +
				`This feature will not work unless you add it to your app.ts pipeline.`,
		);
	}
}

export function toRoutingStrategy(
	routing: NonNullable<AstroConfig['i18n']>['routing'],
	domains: NonNullable<AstroConfig['i18n']>['domains'],
): RoutingStrategies {
	let strategy: RoutingStrategies;
	const hasDomains = domains ? Object.keys(domains).length > 0 : false;
	if (routing === 'manual') {
		strategy = 'manual';
	} else {
		if (!hasDomains) {
			if (routing?.prefixDefaultLocale === true) {
				if (routing.redirectToDefaultLocale) {
					strategy = 'pathname-prefix-always';
				} else {
					strategy = 'pathname-prefix-always-no-redirect';
				}
			} else {
				strategy = 'pathname-prefix-other-locales';
			}
		} else {
			if (routing?.prefixDefaultLocale === true) {
				if (routing.redirectToDefaultLocale) {
					strategy = 'domains-prefix-always';
				} else {
					strategy = 'domains-prefix-always-no-redirect';
				}
			} else {
				strategy = 'domains-prefix-other-locales';
			}
		}
	}

	return strategy;
}

export function codeFrame(src: string, loc: ErrorLocation): string {
	if (!loc || loc.line === undefined || loc.column === undefined) {
		return '';
	}
	const lines = normalizeLF(src)
		.split('\n')
		.map((ln) => ln.replace(/\t/g, '  '));
	// grab 2 lines before, and 3 lines after focused line
	const visibleLines = [];
	for (let n = -2; n <= 2; n++) {
		if (lines[loc.line + n]) visibleLines.push(loc.line + n);
	}
	// figure out gutter width
	let gutterWidth = 0;
	for (const lineNo of visibleLines) {
		let w = `> ${lineNo}`;
		if (w.length > gutterWidth) gutterWidth = w.length;
	}
	// print lines
	let output = '';
	for (const lineNo of visibleLines) {
		const isFocusedLine = lineNo === loc.line - 1;
		output += isFocusedLine ? '> ' : '  ';
		output += `${lineNo + 1} | ${lines[lineNo]}\n`;
		if (isFocusedLine)
			output += `${Array.from({ length: gutterWidth }).join(' ')}  | ${Array.from({
				length: loc.column,
			}).join(' ')}^\n`;
	}
	return output;
}

export async function readBodyWithLimit(request: Request, limit: number): Promise<Uint8Array> {
	const contentLengthHeader = request.headers.get('content-length');
	if (contentLengthHeader) {
		const contentLength = Number.parseInt(contentLengthHeader, 10);
		if (Number.isFinite(contentLength) && contentLength > limit) {
			throw new BodySizeLimitError(limit);
		}
	}

	if (!request.body) return new Uint8Array();
	const reader = request.body.getReader();
	const chunks: Uint8Array[] = [];
	let received = 0;
	while (true) {
		const { done, value } = await reader.read();
		if (done) break;
		if (value) {
			received += value.byteLength;
			if (received > limit) {
				throw new BodySizeLimitError(limit);
			}
			chunks.push(value);
		}
	}
	const buffer = new Uint8Array(received);
	let offset = 0;
	for (const chunk of chunks) {
		buffer.set(chunk, offset);
		offset += chunk.byteLength;
	}
	return buffer;
}

export function getPattern(
	segments: RoutePart[][],
	base: AstroConfig['base'],
	addTrailingSlash: AstroConfig['trailingSlash'],
) {
	const pathname = segments
		.map((segment) => {
			if (segment.length === 1 && segment[0].spread) {
				return '(?:\\/(.*?))?';
			} else {
				return (
					'\\/' +
					segment
						.map((part) => {
							if (part.spread) {
								return '(.*?)';
							} else if (part.dynamic) {
								return '([^/]+?)';
							} else {
								return part.content
									.normalize()
									.replace(/\?/g, '%3F')
									.replace(/#/g, '%23')
									.replace(/%5B/g, '[')
									.replace(/%5D/g, ']')
									.replace(/[.*+?^${}()|[\]\\]/g, '\\$&');
							}
						})
						.join('')
				);
			}
		})
		.join('');

	const trailing =
		addTrailingSlash && segments.length ? getTrailingSlashPattern(addTrailingSlash) : '$';
	let initial = '\\/';
	if (addTrailingSlash === 'never' && base !== '/' && pathname !== '') {
		initial = '';
	}
	// nosemgrep: javascript.lang.security.audit.detect-non-literal-regexp.detect-non-literal-regexp
	// The pattern is assembled from escaped route segments generated by Astro.
	return new RegExp(`^${pathname || initial}${trailing}`);
}

async [PERSIST_SYMBOL]() {
	// Handle session data persistence

	if (!this.#dirty && !this.#toDestroy.size) {
		return;
	}

	const storage = await this.#ensureStorage();

	if (this.#dirty && this.#data) {
		const data = await this.#ensureData();
		this.#toDelete.forEach((key) => data.delete(key));
		const key = this.#ensureSessionID();
		let serialized;
		try {
			serialized = stringify(data);
		} catch (err) {
			throw new AstroError(
				{
					...SessionStorageSaveError,
					message: SessionStorageSaveError.message(
						'The session data could not be serialized.',
						this.#config.driver,
					),
				},
				{ cause: err },
			);
		}
		await storage.setItem(key, serialized);
		this.#dirty = false;
	}

	// Handle destroyed session cleanup
	if (this.#toDestroy.size > 0) {
		const cleanupPromises = [...this.#toDestroy].map((sessionId) =>
			storage.removeItem(sessionId).catch((err) => {
				console.error('Failed to clean up session %s:', sessionId, err);
			}),
		);
		await Promise.all(cleanupPromises);
		this.#toDestroy.clear();
	}
}

constructor({
	cookies,
	config,
	runtimeMode,
	driverFactory,
	mockStorage,
}: {
	cookies: AstroCookies;
	config: SSRManifestSession | undefined;
	runtimeMode: RuntimeMode;
	driverFactory: SessionDriverFactory | null;
	mockStorage: Storage | null;
}) {
	if (!config) {
		throw new AstroError({
			...SessionStorageInitError,
			message: SessionStorageInitError.message(
				'No driver was defined in the session configuration and the adapter did not provide a default driver.',
			),
		});
	}
	this.#cookies = cookies;
	this.#driverFactory = driverFactory;
	const { cookie: cookieConfig = DEFAULT_COOKIE_NAME, ...configRest } = config;
	let cookieConfigObject: AstroCookieSetOptions | undefined;
	if (typeof cookieConfig === 'object') {
		const { name = DEFAULT_COOKIE_NAME, ...rest } = cookieConfig;
		this.#cookieName = name;
		cookieConfigObject = rest;
	} else {
		this.#cookieName = cookieConfig || DEFAULT_COOKIE_NAME;
	}
	this.#cookieConfig = {
		sameSite: 'lax',
		secure: runtimeMode === 'production',
		path: '/',
		...cookieConfigObject,
		httpOnly: true,
	};
	this.#config = configRest;
	if (mockStorage) {
		this.#storage = mockStorage;
	}
}

export function vitePluginSessionDriver({ settings }: { settings: AstroSettings }): VitePlugin {
	return {
		name: VIRTUAL_SESSION_DRIVER_ID,
		enforce: 'pre',

		resolveId: {
			filter: {
				id: new RegExp(`^${VIRTUAL_SESSION_DRIVER_ID}$`),
			},
			handler() {
				return RESOLVED_VIRTUAL_SESSION_DRIVER_ID;
			},
		},

		load: {
			filter: {
				id: new RegExp(`^${RESOLVED_VIRTUAL_SESSION_DRIVER_ID}$`),
			},
			async handler() {
				if (!settings.config.session?.driver) {
					return { code: 'export default null;' };
				}

				const driver = normalizeSessionDriverConfig(
					settings.config.session.driver,
					settings.config.session.options,
				);
				const importerPath = fileURLToPath(import.meta.url);
				const resolved = await this.resolve(driver.entrypoint, importerPath);
				if (!resolved) {
					throw new AstroError({
						...SessionStorageInitError,
						message: SessionStorageInitError.message(
							`Failed to resolve session driver: ${driver.entrypoint}`,
							driver.entrypoint,
						),
					});
				}

				return {
					code: `import { default as _default } from '${resolved.id}';\nexport * from '${resolved.id}';\nexport default _default;`,
				};
			},
		},
	};
}

({ max, min, length, url, includes, startsWith, endsWith }: StringSchema): ValueValidator =>
	(input) => {
		if (typeof input !== 'string') {
			return {
				ok: false,
				errors: ['type'],
			};
		}
		const errors: Array<string> = [];

		if (max !== undefined && !(input.length <= max)) {
			errors.push('max');
		}
		if (min !== undefined && !(input.length >= min)) {
			errors.push('min');
		}
		if (length !== undefined && !(input.length === length)) {
			errors.push('length');
		}
		if (url !== undefined && !URL.canParse(input)) {
			errors.push('url');
		}
		if (includes !== undefined && !input.includes(includes)) {
			errors.push('includes');
		}
		if (startsWith !== undefined && !input.startsWith(startsWith)) {
			errors.push('startsWith');
		}
		if (endsWith !== undefined && !input.endsWith(endsWith)) {
			errors.push('endsWith');
		}

		if (errors.length > 0) {
			return {
				ok: false,
				errors,
			};
		}
		return {
			ok: true,
			value: input,
		};
	}

export function notFound({ base, locales, fallback }: MiddlewarePayload) {
	return function (context: APIContext, response?: Response): Response | undefined {
		if (
			response?.headers.get(REROUTE_DIRECTIVE_HEADER) === 'no' &&
			typeof fallback === 'undefined'
		) {
			return response;
		}

		const url = context.url;
		// We return a 404 if:
		// - the current path isn't a root. e.g. / or /<base>
		// - the URL doesn't contain a locale
		const isRoot = url.pathname === base + '/' || url.pathname === base;
		if (!(isRoot || pathHasLocale(url.pathname, locales))) {
			if (response) {
				response.headers.set(REROUTE_DIRECTIVE_HEADER, 'no');
				return new Response(response.body, {
					status: 404,
					headers: response.headers,
				});
			} else {
				return new Response(null, {
					status: 404,
					headers: {
						[REROUTE_DIRECTIVE_HEADER]: 'no',
					},
				});
			}
		}

		return undefined;
	};
}

function findMatchingImport(
	tagName: string,
	imports: Map<string, Set<ImportSpecifier>>,
): MatchedImport | undefined {
	const tagSpecifier = tagName.split('.')[0];
	for (const [source, specs] of imports) {
		for (const { imported, local } of specs) {
			if (local === tagSpecifier) {
				// If tagName access properties, we need to make sure the returned `name`
				// properly access the properties from `path`
				if (tagSpecifier !== tagName) {
					switch (imported) {
						// Namespace import: "<buttons.Foo.Bar />" => name: "Foo.Bar"
						case '*': {
							const accessPath = tagName.slice(tagSpecifier.length + 1);
							return { name: accessPath, path: source };
						}
						// Default import: "<buttons.Foo.Bar />" => name: "default.Foo.Bar"
						case 'default': {
							// "buttons.Foo.Bar" => "Foo.Bar"
							const accessPath = tagName.slice(tagSpecifier.length + 1);
							return { name: `default.${accessPath}`, path: source };
						}
						// Named import: "<buttons.Foo.Bar />" => name: "buttons.Foo.Bar"
						default: {
							return { name: tagName, path: source };
						}
					}
				}

				return { name: imported, path: source };
			}
		}
	}
}

export async function compileAstro({
	compileProps,
	astroFileToCompileMetadata,
}: CompileAstroOption): Promise<CompileAstroResult> {
	const transformResult = await compile(compileProps);

	const { fileId: file, fileUrl: url } = getFileInfo(
		compileProps.filename,
		compileProps.astroConfig,
	);

	let SUFFIX = '';
	SUFFIX += `\nconst $$file = ${JSON.stringify(file)};\nconst $$url = ${JSON.stringify(
		url,
	)};export { $$file as file, $$url as url };\n`;

	// Add HMR handling in dev mode.
	if (!compileProps.viteConfig.isProduction) {
		let i = 0;
		while (i < transformResult.scripts.length) {
			SUFFIX += `import "${compileProps.filename}?astro&type=script&index=${i}&lang.ts";`;
			i++;
		}
	}

	// Attach compile metadata to map for use by virtual modules
	astroFileToCompileMetadata.set(compileProps.filename, {
		originalCode: compileProps.source,
		css: transformResult.css,
		scripts: transformResult.scripts,
	});

	return {
		...transformResult,
		code: transformResult.code + SUFFIX,
		map: transformResult.map || null,
	};
}

async (): Promise<Service> => {
	const go = new Go();
	const wasm = await instantiateWASM(
		fileURLToPath(new URL('../astro.wasm', import.meta.url)),
		go.importObject
	);
	go.run(wasm.instance);
	const _service: any = (globalThis as any)['@astrojs/compiler'];
	return {
		transform: (input, options) =>
			new Promise((resolve) => {
				try {
					resolve(_service.transform(input, options || {}));
				} catch (err) {
					// Recreate the service next time on panic
					longLivedService = void 0;
					throw err;
				}
			}),
		parse: (input, options) =>
			new Promise((resolve) => resolve(_service.parse(input, options || {})))
				.catch((error) => {
					longLivedService = void 0;
					throw error;
				})
				.then((result: any) => ({ ...result, ast: JSON.parse(result.ast) })),
		convertToTSX: (input, options) => {
			return new Promise((resolve) => resolve(_service.convertToTSX(input, options || {})))
				.catch((error) => {
					longLivedService = void 0;
					throw error;
				})
				.then((result: any) => {
					return { ...result, map: JSON.parse(result.map) };
				});
		},
	};
}
